import 'package:equatable/equatable.dart'; enum MessageType { text, image, file, audio, system } enum MessageStatus { sending, sent, delivered, read, failed } class MessageEntity extends Equatable { final String messageId; final String sessionId; final String senderId; final String senderName; final MessageType type; final MessageStatus status; final String? text; final String? mediaUrl; final DateTime timestamp; const MessageEntity({required this.messageId, required this.sessionId, required this.senderId, required this.senderName, required this.type, this.status = MessageStatus.sent, this.text, this.mediaUrl, required this.timestamp}); @override List<Object?> get props => [messageId]; }
